        internal static Texture2D DiscordLogo => Get("DiscordLogo", DiscordLogoB64);



        private static Texture2D Get(string key, string base64)
        {
            if (_cache == null)
                _cache = new Dictionary<string, Texture2D>();

            if (_cache.TryGetValue(key, out var cached) && cached != null)
                return cached;

            var bytes = System.Convert.FromBase64String(base64);
            var tex = new Texture2D(2, 2, TextureFormat.RGBA32, false);
            tex.LoadImage(bytes);
            tex.hideFlags = HideFlags.HideAndDontSave;
            _cache[key] = tex;
            return tex;
        }

        internal static Texture2D Circle => GetCircle();
        private static Texture2D _circle;
        private static Texture2D GetCircle()
        {
            if (_circle != null) return _circle;
            const int s = 8;
            _circle = new Texture2D(s, s, TextureFormat.RGBA32, false);
            _circle.hideFlags = HideFlags.HideAndDontSave;
            _circle.filterMode = FilterMode.Bilinear;
            float c = s * 0.5f;
            var pixels = new Color[s * s];
            for (int y = 0; y < s; y++)
            for (int x = 0; x < s; x++)
            {
                float dx = x + 0.5f - c, dy = y + 0.5f - c;
                float d = Mathf.Sqrt(dx * dx + dy * dy) / c;
                float a = Mathf.Clamp01(1f - d);
                pixels[y * s + x] = new Color(1, 1, 1, a);
            }
            _circle.SetPixels(pixels);
            _circle.Apply(false, true);
            return _circle;
        }

